import React from "react";
import { useState } from "react";
import { useDispatch, useSelector } from "react-redux"
import { useEffect } from "react";
import itinerariesActions from "../redux/actions/itinerariesActions";
import commentsActions from "../redux/actions/commentsActions"


import AddIcon from '@mui/icons-material/Add'
// import EditIcon from '@mui/icons-material/Edit'

function Comments ({itinerary, cityid}){
    const [comments, setComments] = useState([])
    const [inputText, setInputText] = useState("") 
    const [modifyComment, setModifyComment] = useState("") 
    const [reload, setReload] = useState()
    // const [newButton,setNewButton] = useState(false)

    const dispatch = useDispatch()

    const user = useSelector(store => store.userReducers.user)
    // console.log(user.id);


    // comment functions

    async function addComment(){
        const commentData = {
            itineraryId: itinerary._id,
            comments :{
                comment: inputText,
                userID: user.id
            }
        }
        await dispatch(commentsActions.addComment(commentData))
        setInputText("")
        setReload(!reload)
    }

    async function modifyComments(event){
        const commentData = {
            commentId: event.target.value,
            comments :{
                comment: modifyComment,
                userID: user.id
            }
        }
        await dispatch(commentsActions.modifyComment(commentData))
    }
    // function toChangeInputs() {
    //     setNewButton(true)
    // }

    useEffect(() => {
        dispatch(itinerariesActions.findTinFromCity(cityid))
    }, [reload])

    return(
        <>
        {comments?.map((comment) => 
        <p>{comment.comments}</p>)}
        <textarea rows='2' onChange={(event) => setInputText(event.target.value)} value={inputText} className='myInputforComment fredokaFont' />
                            <AddIcon onClick={addComment} sx={{bgcolor: 'rgb(196, 165, 126)', '&:hover': {bgcolor: 'rgba(196, 165, 126, 0.7)'}, padding: '5px', margin: '5px', marginRigth: '0', color: 'white', width: '30px', height: '30px', borderRadius: '15px'}} />
        </>
    )
}
export default Comments
